import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { GripVertical, Eye, EyeOff, Plus, Edit, Trash2 } from "lucide-react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import type { HomeSlide, HomeWidget, HomeWidgetItem } from "@shared/schema";
import { supabase } from "@/lib/supabase";
import { homeSlideQueries, homeWidgetItemQueries } from "@/lib/supabase-queries";
import { Upload } from "lucide-react";

export default function HomeSettings() {
  const { toast } = useToast();

  const { data: slides = [], isLoading: slidesLoading } = useQuery<HomeSlide[]>({
    queryKey: ['home-slides'],
    queryFn: homeSlideQueries.getAll,
  });

  const { data: widgetItems = [], isLoading: widgetItemsLoading } = useQuery<HomeWidgetItem[]>({
    queryKey: ['home-widget-items'],
    queryFn: homeWidgetItemQueries.getAll,
  });

  const [isSlideDialogOpen, setIsSlideDialogOpen] = useState(false);
  const [isWidgetDialogOpen, setIsWidgetDialogOpen] = useState(false);
  const [editingSlide, setEditingSlide] = useState<HomeSlide | null>(null);
  const [slideForm, setSlideForm] = useState({
    position: 0,
    imageUrl: "",
    redirectUrl: "",
    text: "",
  });

  const [editingWidget, setEditingWidget] = useState<HomeWidgetItem | null>(null);
  const [widgetForm, setWidgetForm] = useState({
    position: 0,
    image: "",
    title: "",
    subtitle: "",
    redirectUrl: "",
  });
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState<number>(0);

  const createSlideMutation = useMutation({
    mutationFn: (data: Partial<HomeSlide>) => homeSlideQueries.create(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['home-slides'] });
      toast({ title: "Slide created successfully" });
    },
    onError: (error: any) => {
      toast({ title: "Error", description: error.message, variant: "destructive" });
    },
  });

  const updateSlideMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: Partial<HomeSlide> }) =>
      homeSlideQueries.update(id, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['home-slides'] });
      toast({ title: "Slide updated successfully" });
    },
    onError: (error: any) => {
      toast({ title: "Error", description: error.message, variant: "destructive" });
    },
  });

  const deleteSlideMutation = useMutation({
    mutationFn: (id: string) => homeSlideQueries.delete(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['home-slides'] });
      toast({ title: "Slide deleted successfully" });
    },
    onError: (error: any) => {
      toast({ title: "Error", description: error.message, variant: "destructive" });
    },
  });

  const createWidgetItemMutation = useMutation({
    mutationFn: (data: Partial<HomeWidgetItem>) => homeWidgetItemQueries.create(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['home-widget-items'] });
      toast({ title: "Widget created successfully" });
    },
    onError: (error: any) => {
      toast({ title: "Error", description: error.message, variant: "destructive" });
    },
  });

  const updateWidgetItemMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: Partial<HomeWidgetItem> }) =>
      homeWidgetItemQueries.update(id, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['home-widget-items'] });
      toast({ title: "Widget updated successfully" });
    },
    onError: (error: any) => {
      toast({ title: "Error", description: error.message, variant: "destructive" });
    },
  });

  const deleteWidgetItemMutation = useMutation({
    mutationFn: (id: string) => homeWidgetItemQueries.delete(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['home-widget-items'] });
      toast({ title: "Widget deleted successfully" });
    },
    onError: (error: any) => {
      toast({ title: "Error", description: error.message, variant: "destructive" });
    },
  });


  const handleCreateSlide = () => {
    setEditingSlide(null);
    setSlideForm({ position: slides.length, imageUrl: "", redirectUrl: "", text: "" });
    setIsSlideDialogOpen(true);
  };

  const handleEditSlide = (slide: HomeSlide) => {
    setEditingSlide(slide);
    setSlideForm({
      position: slide.position,
      imageUrl: slide.imageUrl,
      redirectUrl: slide.redirectUrl,
      text: slide.text || "",
    });
    setIsSlideDialogOpen(true);
  };

  const handleDeleteSlide = (id: string) => {
    deleteSlideMutation.mutate(id);
  };

  const handleCreateWidget = () => {
    setEditingWidget(null);
    setWidgetForm({ position: widgetItems.length, image: "", title: "", subtitle: "", redirectUrl: "" });
    setIsWidgetDialogOpen(true);
  };

  const handleEditWidget = (widget: HomeWidgetItem) => {
    setEditingWidget(widget);
    setWidgetForm({
      position: widget.position,
      image: widget.image,
      title: widget.title,
      subtitle: widget.subtitle || "",
      redirectUrl: widget.redirectUrl,
    });
    setIsWidgetDialogOpen(true);
  };

  const handleDeleteWidget = (id: string) => {
    deleteWidgetItemMutation.mutate(id);
  };

  const handleSaveWidget = () => {
    if (editingWidget) {
      updateWidgetItemMutation.mutate({
        id: editingWidget.id,
        data: widgetForm,
      });
    } else {
      createWidgetItemMutation.mutate(widgetForm);
    }
    setIsWidgetDialogOpen(false);
  };

  const handleImageUpload = async (event: React.ChangeEvent<HTMLInputElement>, formType: 'slide' | 'widget') => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith('image/')) {
      toast({
        variant: "destructive",
        title: "Invalid file type",
        description: "Please upload an image file",
      });
      return;
    }

    setIsUploading(true);
    setUploadProgress(0);

    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Math.random().toString(36).substring(2)}-${Date.now()}.${fileExt}`;
      const folderName = formType === 'slide' ? 'slides' : 'widgets';
      const filePath = `${folderName}/${fileName}`;

      const { data, error } = await supabase.storage
        .from('home-slides')
        .upload(filePath, file, {
          cacheControl: '3600',
          upsert: false
        });

      if (error) {
        if (error.message.includes('Bucket not found')) {
          const { error: bucketError } = await supabase.storage.createBucket('home-slides', {
            public: true,
            fileSizeLimit: 5242880
          });

          if (bucketError && !bucketError.message.includes('already exists')) {
            throw bucketError;
          }

          const { data: retryData, error: retryError } = await supabase.storage
            .from('home-slides')
            .upload(filePath, file, {
              cacheControl: '3600',
              upsert: false
            });

          if (retryError) throw retryError;

          const { data: { publicUrl } } = supabase.storage
            .from('home-slides')
            .getPublicUrl(retryData.path);

          if (formType === 'slide') {
            setSlideForm({ ...slideForm, imageUrl: publicUrl });
          } else {
            setWidgetForm({ ...widgetForm, image: publicUrl });
          }
          toast({
            title: "Upload successful",
            description: "Image uploaded to storage",
          });
        } else {
          throw error;
        }
      } else {
        const { data: { publicUrl } } = supabase.storage
          .from('home-slides')
          .getPublicUrl(data.path);

        if (formType === 'slide') {
          setSlideForm({ ...slideForm, imageUrl: publicUrl });
        } else {
          setWidgetForm({ ...widgetForm, image: publicUrl });
        }
        toast({
          title: "Upload successful",
          description: "Image uploaded to storage",
        });
      }
    } catch (error: any) {
      console.error('Upload error:', error);
      toast({
        variant: "destructive",
        title: "Upload failed",
        description: error.message || "Failed to upload image",
      });
    } finally {
      setIsUploading(false);
      setUploadProgress(0);
    }
  };

  const handleSaveSlide = () => {
    if (editingSlide) {
      updateSlideMutation.mutate(
        { id: editingSlide.id, data: slideForm },
        { onSuccess: () => setIsSlideDialogOpen(false) }
      );
    } else {
      createSlideMutation.mutate(slideForm, {
        onSuccess: () => setIsSlideDialogOpen(false),
      });
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white" data-testid="text-page-title">Home Layout Settings</h1>
          <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
            Manage home page slides and widget layout
          </p>
        </div>
      </div>

      <Card>
        <CardHeader className="border-b border-gray-200 dark:border-gray-700">
          <div className="flex justify-between items-center">
            <CardTitle className="text-lg">Home Slides</CardTitle>
            <Button onClick={handleCreateSlide} data-testid="button-create-slide">
              <Plus className="h-4 w-4 mr-2" />
              Add Slide
            </Button>
          </div>
        </CardHeader>
        <CardContent className="p-0">
          {slides.length === 0 ? (
            <div className="p-8 text-center text-gray-500 dark:text-gray-400">
              No slides configured. Click "Add Slide" to create one.
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-sm text-left">
                <thead className="text-xs text-gray-700 dark:text-gray-400 uppercase bg-gray-50 dark:bg-gray-700">
                  <tr>
                    <th className="px-6 py-3">Position</th>
                    <th className="px-6 py-3">Text</th>
                    <th className="px-6 py-3">Image</th>
                    <th className="px-6 py-3">Redirect URL</th>
                    <th className="px-6 py-3">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {slides.sort((a, b) => a.position - b.position).map((slide) => (
                    <tr
                      key={slide.id}
                      className="border-b border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700"
                      data-testid={`slide-row-${slide.id}`}
                    >
                      <td className="px-6 py-4 font-medium text-gray-900 dark:text-white">
                        {slide.position}
                      </td>
                      <td className="px-6 py-4 text-gray-900 dark:text-white max-w-[200px]">
                        {slide.text || "-"}
                      </td>
                      <td className="px-6 py-4">
                        <img 
                          src={slide.imageUrl} 
                          alt={slide.text || "Slide image"} 
                          className="h-16 w-24 object-cover rounded border border-gray-200 dark:border-gray-600"
                          data-testid={`img-slide-${slide.id}`}
                        />
                      </td>
                      <td className="px-6 py-4 text-gray-500 dark:text-gray-400 max-w-[250px]">
                        {slide.redirectUrl}
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => handleEditSlide(slide)}
                            data-testid={`button-edit-slide-${slide.id}`}
                            className="text-blue-600 hover:text-blue-700 hover:bg-blue-50"
                          >
                            <Edit className="h-4 w-4" />
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => handleDeleteSlide(slide.id)}
                            data-testid={`button-delete-slide-${slide.id}`}
                            className="text-red-600 hover:text-red-700 hover:bg-red-50"
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="border-b border-gray-200 dark:border-gray-700">
          <div className="flex justify-between items-center">
            <CardTitle className="text-lg">Home Widget</CardTitle>
            <Button onClick={handleCreateWidget} data-testid="button-create-widget">
              <Plus className="h-4 w-4 mr-2" />
              Add Widget
            </Button>
          </div>
        </CardHeader>
        <CardContent className="p-0">
          {widgetItems.length === 0 ? (
            <div className="p-8 text-center text-gray-500 dark:text-gray-400">
              No widgets configured. Click "Add Widget" to create one.
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-sm text-left">
                <thead className="text-xs text-gray-700 dark:text-gray-400 uppercase bg-gray-50 dark:bg-gray-700">
                  <tr>
                    <th className="px-6 py-3">Position</th>
                    <th className="px-6 py-3">Image</th>
                    <th className="px-6 py-3">Title</th>
                    <th className="px-6 py-3">Subtitle</th>
                    <th className="px-6 py-3">Redirect URL</th>
                    <th className="px-6 py-3">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {widgetItems.sort((a, b) => a.position - b.position).map((item) => (
                    <tr
                      key={item.id}
                      className="border-b border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700"
                      data-testid={`widget-row-${item.id}`}
                    >
                      <td className="px-6 py-4 font-medium text-gray-900 dark:text-white">
                        {item.position}
                      </td>
                      <td className="px-6 py-4">
                        <img 
                          src={item.image} 
                          alt={item.title} 
                          className="h-16 w-24 object-cover rounded border border-gray-200 dark:border-gray-600"
                          data-testid={`img-widget-${item.id}`}
                        />
                      </td>
                      <td className="px-6 py-4 text-gray-900 dark:text-white max-w-[200px]">
                        {item.title}
                      </td>
                      <td className="px-6 py-4 text-gray-500 dark:text-gray-400 max-w-[200px]">
                        {item.subtitle || "-"}
                      </td>
                      <td className="px-6 py-4 text-gray-500 dark:text-gray-400 max-w-[250px]">
                        {item.redirectUrl}
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => handleEditWidget(item)}
                            data-testid={`button-edit-widget-${item.id}`}
                            className="text-blue-600 hover:text-blue-700 hover:bg-blue-50"
                          >
                            <Edit className="h-4 w-4" />
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => handleDeleteWidget(item.id)}
                            data-testid={`button-delete-widget-${item.id}`}
                            className="text-red-600 hover:text-red-700 hover:bg-red-50"
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </CardContent>
      </Card>

      <Dialog open={isSlideDialogOpen} onOpenChange={setIsSlideDialogOpen}>
        <DialogContent data-testid="dialog-slide-form">
          <DialogHeader>
            <DialogTitle>{editingSlide ? "Edit Slide" : "Create New Slide"}</DialogTitle>
            <DialogDescription>
              {editingSlide ? "Update slide details" : "Add a new slide to the home page"}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="position">Position</Label>
              <Input
                id="position"
                type="number"
                min="0"
                placeholder="0"
                value={slideForm.position}
                onChange={(e) => setSlideForm({ ...slideForm, position: parseInt(e.target.value) || 0 })}
                data-testid="input-slide-position"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="text">Text</Label>
              <Input
                id="text"
                type="text"
                placeholder="Slide title or description"
                value={slideForm.text}
                onChange={(e) => setSlideForm({ ...slideForm, text: e.target.value })}
                data-testid="input-slide-text"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="imageUrl">Image</Label>
              <div className="flex gap-2">
                <Input
                  id="imageUrl"
                  type="url"
                  placeholder="https://example.com/slide.jpg"
                  value={slideForm.imageUrl}
                  onChange={(e) => setSlideForm({ ...slideForm, imageUrl: e.target.value })}
                  data-testid="input-slide-image"
                  className="flex-1"
                />
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => document.getElementById('file-upload')?.click()}
                  disabled={isUploading}
                  data-testid="button-upload-image"
                >
                  <Upload className="h-4 w-4 mr-2" />
                  {isUploading ? "Uploading..." : "Upload"}
                </Button>
                <input
                  id="file-upload"
                  type="file"
                  accept="image/*"
                  onChange={(e) => handleImageUpload(e, 'slide')}
                  className="hidden"
                  data-testid="input-file-upload"
                />
              </div>
              <p className="text-xs text-gray-500 dark:text-gray-400">
                Upload an image or paste a URL
              </p>
            </div>
            <div className="space-y-2">
              <Label htmlFor="redirectUrl">Redirect URL</Label>
              <Input
                id="redirectUrl"
                type="url"
                placeholder="https://example.com/destination"
                value={slideForm.redirectUrl}
                onChange={(e) => setSlideForm({ ...slideForm, redirectUrl: e.target.value })}
                data-testid="input-slide-redirect"
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsSlideDialogOpen(false)} data-testid="button-cancel">
              Cancel
            </Button>
            <Button onClick={handleSaveSlide} data-testid="button-save-slide">
              {editingSlide ? "Save Changes" : "Create Slide"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={isWidgetDialogOpen} onOpenChange={setIsWidgetDialogOpen}>
        <DialogContent data-testid="dialog-widget-form">
          <DialogHeader>
            <DialogTitle>{editingWidget ? "Edit Widget" : "Create New Widget"}</DialogTitle>
            <DialogDescription>
              {editingWidget ? "Update widget details" : "Add a new widget to the home page"}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="widget-position">Position</Label>
              <Input
                id="widget-position"
                type="number"
                min="0"
                placeholder="0"
                value={widgetForm.position}
                onChange={(e) => setWidgetForm({ ...widgetForm, position: parseInt(e.target.value) || 0 })}
                data-testid="input-widget-position"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="widget-title">Title</Label>
              <Input
                id="widget-title"
                type="text"
                placeholder="Widget title"
                value={widgetForm.title}
                onChange={(e) => setWidgetForm({ ...widgetForm, title: e.target.value })}
                data-testid="input-widget-title"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="widget-subtitle">Subtitle</Label>
              <Input
                id="widget-subtitle"
                type="text"
                placeholder="Widget subtitle (optional)"
                value={widgetForm.subtitle}
                onChange={(e) => setWidgetForm({ ...widgetForm, subtitle: e.target.value })}
                data-testid="input-widget-subtitle"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="widget-image">Image</Label>
              <div className="flex gap-2">
                <Input
                  id="widget-image"
                  type="url"
                  placeholder="https://example.com/widget.jpg"
                  value={widgetForm.image}
                  onChange={(e) => setWidgetForm({ ...widgetForm, image: e.target.value })}
                  data-testid="input-widget-image"
                  className="flex-1"
                />
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => document.getElementById('widget-file-upload')?.click()}
                  disabled={isUploading}
                  data-testid="button-upload-widget-image"
                >
                  <Upload className="h-4 w-4 mr-2" />
                  {isUploading ? "Uploading..." : "Upload"}
                </Button>
                <input
                  id="widget-file-upload"
                  type="file"
                  accept="image/*"
                  onChange={(e) => handleImageUpload(e, 'widget')}
                  className="hidden"
                  data-testid="input-widget-file-upload"
                />
              </div>
              {widgetForm.image && (
                <div className="mt-2">
                  <img 
                    src={widgetForm.image} 
                    alt="Widget preview" 
                    className="h-32 w-48 object-cover rounded border border-gray-200 dark:border-gray-600"
                    data-testid="img-widget-preview"
                  />
                </div>
              )}
              <p className="text-xs text-gray-500 dark:text-gray-400">
                Upload an image or paste a URL
              </p>
            </div>
            <div className="space-y-2">
              <Label htmlFor="widget-redirect">Redirect URL</Label>
              <Input
                id="widget-redirect"
                type="url"
                placeholder="https://example.com/destination"
                value={widgetForm.redirectUrl}
                onChange={(e) => setWidgetForm({ ...widgetForm, redirectUrl: e.target.value })}
                data-testid="input-widget-redirect"
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsWidgetDialogOpen(false)} data-testid="button-widget-cancel">
              Cancel
            </Button>
            <Button onClick={handleSaveWidget} data-testid="button-save-widget">
              {editingWidget ? "Save Changes" : "Create Widget"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/pages/huddle-management.tsx.content:
import { useState, useEffect } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Plus, Calendar as CalendarIcon, Clock, Trash2, Upload, Link as LinkIcon } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useToast } from "@/hooks/use-toast";
import { queryClient } from "@/lib/queryClient";
import { huddleQueries } from "@/lib/supabase-queries";
import { supabase } from "@/lib/supabase";
import type { Huddle, InsertHuddle } from "@shared/schema";

export default function HuddleManagement() {
  const { toast } = useToast();
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingHuddle, setEditingHuddle] = useState<Huddle | null>(null);
  const [nextHuddle, setNextHuddle] = useState<Huddle | null>(null);
  const [countdown, setCountdown] = useState("");
  const [imagePreview, setImagePreview] = useState<string>("");
  const [uploadingImage, setUploadingImage] = useState(false);

  const [formData, setFormData] = useState({
    title: "",
    description: "",
    scheduledAt: "",
    duration: 30,
    status: "upcoming",
    image: "",
  });

  const { data: huddles = [], isLoading } = useQuery({
    queryKey: ['/api/huddles'],
    queryFn: () => huddleQueries.getAll(),
  });

  const createMutation = useMutation({
    mutationFn: (huddle: InsertHuddle) => huddleQueries.create(huddle),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/huddles'] });
      toast({ title: "Success", description: "Huddle scheduled successfully" });
      setIsDialogOpen(false);
      resetForm();
    },
    onError: (error: any) => {
      toast({ 
        title: "Error", 
        description: error.message || "Failed to schedule huddle",
        variant: "destructive" 
      });
    },
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: Partial<Huddle> }) => 
      huddleQueries.update(id, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/huddles'] });
      toast({ title: "Success", description: "Huddle updated successfully" });
      setIsDialogOpen(false);
      setEditingHuddle(null);
      resetForm();
    },
    onError: (error: any) => {
      toast({ 
        title: "Error", 
        description: error.message || "Failed to update huddle",
        variant: "destructive" 
      });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => huddleQueries.delete(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/huddles'] });
      toast({ title: "Success", description: "Huddle deleted successfully" });
    },
    onError: (error: any) => {
      toast({ 
        title: "Error", 
        description: error.message || "Failed to delete huddle",
        variant: "destructive" 
      });
    },
  });

  const resetForm = () => {
    setFormData({
      title: "",
      description: "",
      scheduledAt: "",
      duration: 30,
      status: "upcoming",
      image: "",
    });
    setImagePreview("");
  };

  const handleOpenDialog = (huddle?: Huddle) => {
    if (huddle) {
      setEditingHuddle(huddle);
      setFormData({
        title: huddle.title,
        description: huddle.description || "",
        scheduledAt: new Date(huddle.scheduledAt).toISOString().slice(0, 16),
        duration: huddle.duration,
        status: huddle.status,
        image: huddle.image || "",
      });
      setImagePreview(huddle.image || "");
    } else {
      setEditingHuddle(null);
      resetForm();
    }
    setIsDialogOpen(true);
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      toast({
        title: "File too large",
        description: "Image must be less than 5MB",
        variant: "destructive"
      });
      return;
    }

    setUploadingImage(true);

    try {
      const fileName = `huddle-${Date.now()}-${file.name.replace(/\s+/g, '-').replace(/[^a-zA-Z0-9.-]/g, '')}`;
      const { data, error } = await supabase.storage
        .from('recipe-images')
        .upload(fileName, file);

      if (error) {
        if (error.message.includes('Bucket not found')) {
          toast({
            title: "Storage Not Configured",
            description: "Please create 'recipe-images' bucket in Supabase Storage with public access policies.",
            variant: "destructive",
            duration: 10000,
          });
        } else {
          throw error;
        }
        return;
      }

      const { data: { publicUrl } } = supabase.storage
        .from('recipe-images')
        .getPublicUrl(fileName);

      setFormData({ ...formData, image: publicUrl });
      setImagePreview(publicUrl);
      toast({ title: "Success", description: "Image uploaded successfully" });
    } catch (error: any) {
      toast({
        title: "Upload failed",
        description: error.message,
        variant: "destructive"
      });
    } finally {
      setUploadingImage(false);
    }
  };

  const handleImageUrlChange = (url: string) => {
    setFormData({ ...formData, image: url });
    setImagePreview(url);
  };

  const handleSubmit = () => {
    if (!formData.title || !formData.scheduledAt) {
      toast({
        title: "Validation Error",
        description: "Please fill in all required fields",
        variant: "destructive"
      });
      return;
    }

    const huddleData = {
      title: formData.title,
      description: formData.description,
      scheduledAt: new Date(formData.scheduledAt),
      duration: formData.duration,
      status: formData.status,
      image: formData.image,
    };

    if (editingHuddle) {
      updateMutation.mutate({ id: editingHuddle.id, data: huddleData });
    } else {
      createMutation.mutate(huddleData);
    }
  };

  useEffect(() => {
    if (!huddles.length) return;

    const upcoming = huddles
      .filter(h => h.status === "upcoming")
      .sort((a, b) => new Date(a.scheduledAt).getTime() - new Date(b.scheduledAt).getTime())[0];
    setNextHuddle(upcoming);
  }, [huddles]);

  useEffect(() => {
    if (!nextHuddle) return;

    const timer = setInterval(() => {
      const now = new Date();
      const diff = new Date(nextHuddle.scheduledAt).getTime() - now.getTime();

      if (diff <= 0) {
        setCountdown("Starting now!");
        return;
      }

      const days = Math.floor(diff / (1000 * 60 * 60 * 24));
      const hours = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
      const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
      const seconds = Math.floor((diff % (1000 * 60)) / 1000);

      setCountdown(`${days > 0 ? `${days}d ` : ""}${hours}h ${minutes}m ${seconds}s`);
    }, 1000);

    return () => clearInterval(timer);
  }, [nextHuddle]);

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-start gap-4">
        <div>
          <h1 className="text-2xl font-semibold" data-testid="text-page-title">Huddle Management</h1>
          <p className="text-sm text-muted-foreground mt-1">
            Schedule and manage team meetings
          </p>
        </div>
        <Button onClick={() => handleOpenDialog()} data-testid="button-create-huddle">
          <Plus className="h-4 w-4 mr-2" />
          Schedule Huddle
        </Button>
      </div>

      {nextHuddle && (
        <Card className="relative overflow-hidden border-primary/20">
          {nextHuddle.image && (
            <>
              <div 
                className="absolute inset-0 bg-cover bg-center"
                style={{ backgroundImage: `url(${nextHuddle.image})` }}
              />
              <div className="absolute inset-0 bg-gradient-to-br from-black/70 to-black/50" />
            </>
          )}
          <div className="relative">
            <CardHeader className="pb-3">
              <CardTitle className="text-lg flex items-center gap-2 text-white">
                <CalendarIcon className="h-5 w-5" />
                Next Huddle
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-3">
                <div>
                  <div className="font-semibold text-lg text-white" data-testid="text-next-huddle-title">{nextHuddle.title}</div>
                  <p className="text-sm text-white/80">{nextHuddle.description}</p>
                </div>
                <div className="text-3xl font-bold font-mono tracking-tight text-white" data-testid="text-huddle-countdown">
                  {countdown || "Loading..."}
                </div>
                <div className="flex items-center gap-4 text-sm text-white/80">
                  <div className="flex items-center gap-1">
                    <CalendarIcon className="h-4 w-4" />
                    {new Date(nextHuddle.scheduledAt).toLocaleString('en-US', {
                      month: 'short',
                      day: 'numeric',
                      hour: '2-digit',
                      minute: '2-digit'
                    })}
                  </div>
                  <div className="flex items-center gap-1">
                    <Clock className="h-4 w-4" />
                    {nextHuddle.duration} min
                  </div>
                </div>
              </div>
            </CardContent>
          </div>
        </Card>
      )}

      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Upcoming Huddles</CardTitle>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="text-center py-8 text-muted-foreground">Loading huddles...</div>
          ) : huddles.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">No huddles scheduled yet</div>
          ) : (
            <div className="space-y-3">
              {huddles.map((huddle) => (
                <div
                  key={huddle.id}
                  className="p-4 rounded-md border hover-elevate"
                  data-testid={`huddle-item-${huddle.id}`}
                >
                  <div className="flex justify-between items-start gap-4">
                    <div className="flex gap-4 flex-1">
                      {huddle.image && (
                        <img 
                          src={huddle.image} 
                          alt={huddle.title}
                          className="w-16 h-16 rounded-md object-cover"
                        />
                      )}
                      <div className="flex-1">
                        <div className="flex items-center gap-2 mb-1">
                          <div className="font-medium">{huddle.title}</div>
                          <Badge variant="outline">{huddle.status}</Badge>
                        </div>
                        <p className="text-sm text-muted-foreground mb-2">
                          {huddle.description}
                        </p>
                        <div className="flex items-center gap-4 text-xs text-muted-foreground">
                          <div className="flex items-center gap-1">
                            <CalendarIcon className="h-3 w-3" />
                            {new Date(huddle.scheduledAt).toLocaleString('en-US', {
                              weekday: 'short',
                              month: 'short',
                              day: 'numeric',
                              hour: '2-digit',
                              minute: '2-digit'
                            })}
                          </div>
                          <div className="flex items-center gap-1">
                            <Clock className="h-3 w-3" />
                            {huddle.duration} min
                          </div>
                        </div>
                      </div>
                    </div>
                    <div className="flex gap-2">
                      <Button 
                        variant="ghost" 
                        size="sm" 
                        onClick={() => handleOpenDialog(huddle)}
                        data-testid={`button-edit-huddle-${huddle.id}`}
                      >
                        Edit
                      </Button>
                      <Button 
                        variant="ghost" 
                        size="sm"
                        onClick={() => deleteMutation.mutate(huddle.id)}
                        disabled={deleteMutation.isPending}
                        data-testid={`button-delete-huddle-${huddle.id}`}
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto" data-testid="dialog-huddle-form">
          <DialogHeader>
            <DialogTitle>{editingHuddle ? "Edit Huddle" : "Schedule New Huddle"}</DialogTitle>
            <DialogDescription>
              {editingHuddle ? "Update huddle details" : "Create a new team meeting"}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="title">Title *</Label>
              <Input 
                id="title" 
                placeholder="Team Standup" 
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                data-testid="input-huddle-title" 
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="description">Description</Label>
              <Textarea 
                id="description" 
                placeholder="What will this huddle be about?" 
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                data-testid="input-huddle-description" 
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="date">Date & Time *</Label>
                <Input 
                  id="date" 
                  type="datetime-local" 
                  value={formData.scheduledAt || ''}
                  onChange={(e) => setFormData({ ...formData, scheduledAt: e.target.value })}
                  min={new Date().toISOString().slice(0, 16)}
                  data-testid="input-huddle-datetime" 
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="duration">Duration (minutes) *</Label>
                <Input 
                  id="duration" 
                  type="number" 
                  placeholder="30" 
                  value={formData.duration}
                  onChange={(e) => setFormData({ ...formData, duration: Number(e.target.value) })}
                  data-testid="input-huddle-duration" 
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label>Huddle Image</Label>
              <Tabs defaultValue="upload" className="w-full">
                <TabsList className="grid w-full grid-cols-2">
                  <TabsTrigger value="upload" data-testid="tab-upload">
                    <Upload className="h-4 w-4 mr-2" />
                    Upload
                  </TabsTrigger>
                  <TabsTrigger value="url" data-testid="tab-url">
                    <LinkIcon className="h-4 w-4 mr-2" />
                    URL
                  </TabsTrigger>
                </TabsList>
                <TabsContent value="upload" className="space-y-2">
                  <Input
                    type="file"
                    accept="image/*"
                    onChange={handleImageUpload}
                    disabled={uploadingImage}
                    data-testid="input-image-upload"
                  />
                  {uploadingImage && (
                    <p className="text-sm text-muted-foreground">Uploading image...</p>
                  )}
                </TabsContent>
                <TabsContent value="url" className="space-y-2">
                  <Input
                    placeholder="https://example.com/image.jpg"
                    value={formData.image}
                    onChange={(e) => handleImageUrlChange(e.target.value)}
                    data-testid="input-image-url"
                  />
                </TabsContent>
              </Tabs>
              {imagePreview && (
                <div className="mt-2">
                  <img
                    src={imagePreview}
                    alt="Preview"
                    className="w-full h-48 object-cover rounded-md"
                    data-testid="img-preview"
                  />
                </div>
              )}
            </div>
          </div>
          <DialogFooter>
            <Button 
              variant="outline" 
              onClick={() => {
                setIsDialogOpen(false);
                setEditingHuddle(null);
                resetForm();
              }} 
              data-testid="button-cancel"
            >
              Cancel
            </Button>
            <Button 
              onClick={handleSubmit}
              disabled={createMutation.isPending || updateMutation.isPending}
              data-testid="button-save-huddle"
            >
              {createMutation.isPending || updateMutation.isPending ? "Saving..." : (editingHuddle ? "Update" : "Schedule")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

