import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { supabase } from "@/lib/supabase";
import { useToast } from "@/hooks/use-toast";
import { userQueries } from "@/lib/supabase-queries";
import logoPath from "@assets/logo_1759609546853.png";
import { Link } from "wouter";

interface SignUpProps {
  onSignUp: () => void;
}

export default function SignUp({ onSignUp }: SignUpProps) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [fullname, setFullname] = useState("");
  const [age, setAge] = useState("");
  const [height, setHeight] = useState("");
  const [weight, setWeight] = useState("");
  const [recipePreference, setRecipePreference] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const { toast } = useToast();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    try {
      const { data, error } = await supabase.auth.signUp({
        email,
        password,
      });

      if (error) {
        toast({
          variant: "destructive",
          title: "Sign up failed",
          description: error.message,
        });
        setIsLoading(false);
        return;
      }

      if (data.user) {
        try {
          await userQueries.create({
            id: data.user.id,
            email: email,
            displayName: fullname,
            role: 'user',
            age,
            height,
            weight,
            recipePreference,
          });

          toast({
            title: "Account created successfully!",
            description: "You can now sign in with your credentials.",
          });

          onSignUp();
        } catch (profileError: any) {
          console.error("Profile creation error:", profileError);
          toast({
            variant: "destructive",
            title: "Profile creation failed",
            description: "Your account was created but the profile couldn't be set up. Please contact support.",
          });
        }
      }
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Error",
        description: "An unexpected error occurred. Please try again.",
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-gray-900 p-4">
      <Card className="w-full max-w-md">
        <CardHeader className="space-y-1 text-center">
          <div className="flex justify-center mb-4">
            <img src={logoPath} alt="QEB Elite Logo" className="h-16" />
          </div>
          <CardTitle className="text-2xl font-bold">Create your account</CardTitle>
          <CardDescription>
            Fill in your details to get started
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="email">Email</Label>
              <Input
                id="email"
                type="email"
                placeholder="name@company.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                data-testid="input-email"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="password">Password</Label>
              <Input
                id="password"
                type="password"
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                minLength={6}
                data-testid="input-password"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="fullname">Full Name</Label>
              <Input
                id="fullname"
                type="text"
                placeholder="John Doe"
                value={fullname}
                onChange={(e) => setFullname(e.target.value)}
                required
                data-testid="input-fullname"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="age">Age</Label>
                <Input
                  id="age"
                  type="text"
                  placeholder="25"
                  value={age}
                  onChange={(e) => setAge(e.target.value)}
                  data-testid="input-age"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="height">Height</Label>
                <Input
                  id="height"
                  type="text"
                  placeholder="5'10&quot;"
                  value={height}
                  onChange={(e) => setHeight(e.target.value)}
                  data-testid="input-height"
                />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="weight">Weight</Label>
                <Input
                  id="weight"
                  type="text"
                  placeholder="180 lbs"
                  value={weight}
                  onChange={(e) => setWeight(e.target.value)}
                  data-testid="input-weight"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="recipePreference">Recipe Pref.</Label>
                <Input
                  id="recipePreference"
                  type="text"
                  placeholder="Vegan"
                  value={recipePreference}
                  onChange={(e) => setRecipePreference(e.target.value)}
                  data-testid="input-recipe-preference"
                />
              </div>
            </div>
            <Button type="submit" className="w-full" disabled={isLoading} data-testid="button-sign-up">
              {isLoading ? "Creating account..." : "Sign up"}
            </Button>
            <div className="text-center text-sm">
              Already have an account?{" "}
              <Link href="/sign-in" className="text-primary hover:underline" data-testid="link-sign-in">
                Sign in
              </Link>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

supabase/generate-schema.ts.content:
import postgres from "postgres";
import { writeFileSync } from "fs";
import { join } from "path";

if (process.env.NODE_ENV === "development") {
  process.env.NODE_TLS_REJECT_UNAUTHORIZED = "0";
}

async function generateSchema() {
  console.log("📊 Generating Supabase schema...");

  const supabaseClient = postgres(process.env.SUPABASE_DB_CONNECTION_STRING!, { 
    prepare: false, 
    ssl: 'require',
    max: 1,
    idle_timeout: 20,
    connect_timeout: 10
  });

  try {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').split('T')[0];
    const revisionTimestamp = new Date().toISOString().replace(/[:.]/g, '-').replace('T', '_').split('.')[0];

    console.log("Fetching table schemas...");

    const tables = await supabaseClient`
      SELECT 
        table_name,
        table_schema
      FROM information_schema.tables 
      WHERE table_schema = 'public'
      ORDER BY table_name`;

    let schemaSQL = `-- Supabase Schema Export
-- Generated: ${new Date().toISOString()}
-- Database: QEB Elite Admin Dashboard

`;

    for (const table of tables) {
      console.log(`  📋 Exporting table: ${table.table_name}`);

      const columns = await supabaseClient`
        SELECT 
          column_name,
          data_type,
          character_maximum_length,
          column_default,
          is_nullable
        FROM information_schema.columns
        WHERE table_schema = 'public' 
        AND table_name = ${table.table_name}
        ORDER BY ordinal_position`;

      schemaSQL += `-- Table: ${table.table_name}\n`;
      schemaSQL += `CREATE TABLE IF NOT EXISTS ${table.table_name} (\n`;

      const columnDefs = columns.map((col: any) => {
        let def = `  ${col.column_name} ${col.data_type}`;

        if (col.character_maximum_length) {
          def += `(${col.character_maximum_length})`;
        }

        if (col.column_default) {
          def += ` DEFAULT ${col.column_default}`;
        }

        if (col.is_nullable === 'NO') {
          def += ' NOT NULL';
        }

        return def;
      });

      schemaSQL += columnDefs.join(',\n');
      schemaSQL += `\n);\n\n`;
    }

    console.log("Fetching storage buckets...");

    const buckets = await supabaseClient`
      SELECT id, name, public
      FROM storage.buckets`;

    if (buckets.length > 0) {
      schemaSQL += `-- Storage Buckets\n`;
      for (const bucket of buckets) {
        schemaSQL += `-- Bucket: ${bucket.name} (${bucket.public ? 'public' : 'private'})\n`;
        schemaSQL += `INSERT INTO storage.buckets (id, name, public)\n`;
        schemaSQL += `VALUES ('${bucket.id}', '${bucket.name}', ${bucket.public})\n`;
        schemaSQL += `ON CONFLICT (id) DO NOTHING;\n\n`;
      }
    }

    console.log("Fetching storage policies...");

    const policies = await supabaseClient`
      SELECT 
        policyname,
        tablename,
        cmd,
        qual,
        with_check
      FROM pg_policies
      WHERE schemaname = 'storage'`;

    if (policies.length > 0) {
      schemaSQL += `-- Storage Policies\n`;
      for (const policy of policies) {
        schemaSQL += `-- Policy: ${policy.policyname} on ${policy.tablename}\n`;
        const command = policy.cmd === '*' ? 'ALL' : policy.cmd;
        schemaSQL += `CREATE POLICY IF NOT EXISTS "${policy.policyname}"\n`;
        schemaSQL += `ON storage.${policy.tablename} FOR ${command}\n`;
        if (policy.qual) {
          schemaSQL += `USING (${policy.qual})\n`;
        }
        if (policy.with_check) {
          schemaSQL += `WITH CHECK (${policy.with_check})\n`;
        }
        schemaSQL += `;\n\n`;
      }
    }

    const schemaPath = join(process.cwd(), 'supabase', 'schema.sql');
    writeFileSync(schemaPath, schemaSQL);
    console.log(`✅ Schema saved to: ${schemaPath}`);

    const revisionPath = join(process.cwd(), 'supabase', 'revisions', `revision_${revisionTimestamp}.sql`);
    writeFileSync(revisionPath, schemaSQL);
    console.log(`✅ Revision saved to: ${revisionPath}`);

    const revisionIndex = join(process.cwd(), 'supabase', 'revisions', 'index.txt');
    const revisionEntry = `${revisionTimestamp} - Schema revision\n`;

    try {
      const { readFileSync } = await import('fs');
      const existing = readFileSync(revisionIndex, 'utf8');
      writeFileSync(revisionIndex, existing + revisionEntry);
    } catch {
      writeFileSync(revisionIndex, revisionEntry);
    }

    console.log(`✅ Revision logged to index`);
    console.log(`\n📦 Summary:`);
    console.log(`   Tables exported: ${tables.length}`);
    console.log(`   Storage buckets: ${buckets.length}`);
    console.log(`   Storage policies: ${policies.length}`);

  } catch (error) {
    console.error("❌ Failed:", error);
    throw error;
  } finally {
    await supabaseClient.end();
  }
}

generateSchema();

client/src/pages/athlete-resources.tsx.content:
import { useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Plus, Edit, Trash2, ExternalLink, Upload, BookOpen } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { useQuery, useMutation } from "@tanstack/react-query";
import { athleteResourceQueries, storageHelpers } from "@/lib/supabase-queries";
import { Skeleton } from "@/components/ui/skeleton";
import { useToast } from "@/hooks/use-toast";
import { queryClient } from "@/lib/queryClient";
import type { AthleteResource } from "@shared/schema";

export default function AthleteResources() {
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingResource, setEditingResource] = useState<AthleteResource | null>(null);
  const [deleteResource, setDeleteResource] = useState<AthleteResource | null>(null);
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string>("");
  const [isUploadingImage, setIsUploadingImage] = useState(false);

  const [formData, setFormData] = useState({
    title: "",
    description: "",
    image: "",
    externalUrl: "",
  });

  const { toast } = useToast();

  const { data: resources, isLoading } = useQuery({
    queryKey: ['/athlete-resources'],
    queryFn: () => athleteResourceQueries.getAll(),
  });

  const createMutation = useMutation({
    mutationFn: (data: Partial<AthleteResource>) => athleteResourceQueries.create(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/athlete-resources'] });
      toast({
        title: "Success",
        description: "Resource created successfully",
      });
      handleCloseDialog();
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to create resource",
        variant: "destructive",
      });
    },
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: Partial<AthleteResource> }) =>
      athleteResourceQueries.update(id, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/athlete-resources'] });
      toast({
        title: "Success",
        description: "Resource updated successfully",
      });
      handleCloseDialog();
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to update resource",
        variant: "destructive",
      });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => athleteResourceQueries.delete(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/athlete-resources'] });
      toast({
        title: "Success",
        description: "Resource deleted successfully",
      });
      setDeleteResource(null);
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to delete resource",
        variant: "destructive",
      });
    },
  });

  const handleOpenDialog = (resource?: AthleteResource) => {
    if (resource) {
      setEditingResource(resource);
      setFormData({
        title: resource.title,
        description: resource.description,
        image: resource.image,
        externalUrl: resource.externalUrl,
      });
      if (resource.image) {
        setImagePreview(resource.image);
      }
    } else {
      setEditingResource(null);
      setFormData({
        title: "",
        description: "",
        image: "",
        externalUrl: "",
      });
    }
    setImageFile(null);
    setIsDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setIsDialogOpen(false);
    setEditingResource(null);
    setImageFile(null);
    setImagePreview("");
    setFormData({
      title: "",
      description: "",
      image: "",
      externalUrl: "",
    });
  };

  const handleImageFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        toast({
          title: "File too large",
          description: "Image must be less than 5MB",
          variant: "destructive",
        });
        return;
      }
      setImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemoveImage = () => {
    setImageFile(null);
    setImagePreview("");
    setFormData(prev => ({ ...prev, image: "" }));
  };

  const handleSubmit = async () => {
    if (!formData.title.trim() || !formData.description.trim() || !formData.externalUrl.trim()) {
      toast({
        title: "Validation Error",
        description: "Please fill in all required fields (title, description, external URL)",
        variant: "destructive",
      });
      return;
    }

    let imageUrl = formData.image;

    if (!imageFile && !imageUrl.trim()) {
      toast({
        title: "Validation Error",
        description: "Please provide an image (upload or URL)",
        variant: "destructive",
      });
      return;
    }

    if (imageFile) {
      try {
        setIsUploadingImage(true);
        const fileExt = imageFile.name.split('.').pop();
        const sanitizedFileName = imageFile.name
          .replace(/\s+/g, '-')
          .replace(/[^a-zA-Z0-9.-]/g, '');
        const fileName = `${Date.now()}-${sanitizedFileName}`;
        const filePath = `athlete-resources/${fileName}`;

        await storageHelpers.uploadFile('recipe-images', filePath, imageFile);
        imageUrl = storageHelpers.getPublicUrl('recipe-images', filePath);
      } catch (error: any) {
        if (error.message?.includes('Bucket not found')) {
          toast({
            title: "Storage Setup Required",
            description: "The recipe-images bucket is used for athlete resource images. Please create it in Supabase Dashboard: Storage → New Bucket → Name: recipe-images (make it public).",
            variant: "destructive",
            duration: 10000,
          });
        } else {
          toast({
            title: "Upload Failed",
            description: error.message || "Failed to upload image",
            variant: "destructive",
          });
        }
        setIsUploadingImage(false);
        return;
      } finally {
        setIsUploadingImage(false);
      }
    }

    const resourceData: Partial<AthleteResource> = {
      title: formData.title.trim(),
      description: formData.description.trim(),
      image: imageUrl,
      externalUrl: formData.externalUrl.trim(),
    };

    if (editingResource) {
      updateMutation.mutate({ id: editingResource.id, data: resourceData });
    } else {
      createMutation.mutate(resourceData);
    }
  };

  const handleDelete = () => {
    if (deleteResource) {
      deleteMutation.mutate(deleteResource.id);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-semibold" data-testid="text-page-title">Athlete Resources</h1>
          <p className="text-sm text-muted-foreground mt-1">
            Manage external resources and links for athletes
          </p>
        </div>
        <Button onClick={() => handleOpenDialog()} data-testid="button-create-resource">
          <Plus className="h-4 w-4 mr-2" />
          Add Resource
        </Button>
      </div>

      {isLoading ? (
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          {[1, 2, 3, 4, 5, 6].map((i) => (
            <Card key={i} className="overflow-hidden">
              <Skeleton className="h-48 w-full" />
              <CardContent className="p-6 space-y-4">
                <Skeleton className="h-5 w-3/4" />
                <Skeleton className="h-4 w-full" />
                <Skeleton className="h-4 w-5/6" />
              </CardContent>
            </Card>
          ))}
        </div>
      ) : (resources && resources.length > 0) ? (
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          {resources.map((resource) => (
            <Card key={resource.id} className="overflow-hidden hover-elevate" data-testid={`resource-item-${resource.id}`}>
              {resource.image ? (
                <div className="h-48 w-full overflow-hidden bg-muted">
                  <img 
                    src={resource.image} 
                    alt={resource.title}
                    className="h-full w-full object-cover"
                    onError={(e) => {
                      e.currentTarget.style.display = 'none';
                      e.currentTarget.parentElement!.innerHTML = '<div class="flex items-center justify-center h-full w-full bg-muted"><svg class="h-12 w-12 text-muted-foreground" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253"></path></svg></div>';
                    }}
                  />
                </div>
              ) : (
                <div className="h-48 w-full bg-muted flex items-center justify-center">
                  <BookOpen className="h-12 w-12 text-muted-foreground" />
                </div>
              )}
              <CardContent className="p-6 space-y-4">
                <div className="space-y-2">
                  <h3 className="font-semibold text-lg">{resource.title}</h3>
                  <p className="text-sm text-muted-foreground line-clamp-2">{resource.description}</p>
                </div>
                <div className="flex gap-2">
                  <Button 
                    size="sm" 
                    variant="outline" 
                    className="flex-1"
                    onClick={() => window.open(resource.externalUrl, '_blank')}
                    data-testid={`button-open-resource-${resource.id}`}
                  >
                    <ExternalLink className="h-3 w-3 mr-1" />
                    Open Link
                  </Button>
                  <Button 
                    size="sm" 
                    variant="ghost"
                    onClick={() => handleOpenDialog(resource)}
                    data-testid={`button-edit-resource-${resource.id}`}
                  >
                    <Edit className="h-3 w-3" />
                  </Button>
                  <Button 
                    size="sm" 
                    variant="ghost"
                    onClick={() => setDeleteResource(resource)}
                    data-testid={`button-delete-resource-${resource.id}`}
                  >
                    <Trash2 className="h-3 w-3" />
                  </Button>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      ) : (
        <div className="text-center py-12">
          <BookOpen className="h-12 w-12 mx-auto text-muted-foreground mb-3" />
          <h3 className="text-lg font-semibold mb-1">No resources yet</h3>
          <p className="text-sm text-muted-foreground mb-4">Add your first athlete resource to get started</p>
          <Button onClick={() => handleOpenDialog()} data-testid="button-create-first-resource">
            <Plus className="h-4 w-4 mr-2" />
            Add Resource
          </Button>
        </div>
      )}

      <Dialog open={isDialogOpen} onOpenChange={handleCloseDialog}>
        <DialogContent className="max-w-2xl" data-testid="dialog-resource-form">
          <DialogHeader>
            <DialogTitle>{editingResource ? "Edit Resource" : "Add Athlete Resource"}</DialogTitle>
            <DialogDescription>
              {editingResource ? "Update the resource details" : "Add a new resource with image, description, and external link"}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="title">Title *</Label>
              <Input 
                id="title" 
                placeholder="e.g., Training Guide, Nutrition Handbook" 
                value={formData.title}
                onChange={(e) => setFormData(prev => ({ ...prev, title: e.target.value }))}
                data-testid="input-resource-title" 
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="description">Description *</Label>
              <Textarea 
                id="description" 
                placeholder="Brief description of this resource" 
                value={formData.description}
                onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                rows={3}
                data-testid="input-resource-description" 
              />
            </div>

            <div className="space-y-2">
              <Label>Image</Label>

              {imagePreview ? (
                <div className="relative w-full h-48 mx-auto">
                  <div className="h-48 w-full rounded-md overflow-hidden border bg-muted flex items-center justify-center">
                    <img 
                      src={imagePreview} 
                      alt="Preview" 
                      className="h-full w-full object-cover"
                      onError={(e) => {
                        e.currentTarget.src = 'https://images.unsplash.com/photo-1517836357463-d25dfeac3438';
                      }}
                    />
                  </div>
                  <Button
                    type="button"
                    size="sm"
                    variant="destructive"
                    className="absolute top-2 right-2 h-8 w-8 rounded-md p-0"
                    onClick={handleRemoveImage}
                    data-testid="button-remove-image"
                  >
                    ×
                  </Button>
                </div>
              ) : (
                <div className="border-2 border-dashed rounded-md p-6 text-center">
                  <BookOpen className="h-8 w-8 mx-auto mb-2 text-muted-foreground" />
                  <p className="text-sm text-muted-foreground mb-3">Upload an image or paste a URL</p>
                  <Button
                    type="button"
                    size="sm"
                    variant="outline"
                    onClick={() => document.getElementById('image-file-input')?.click()}
                    data-testid="button-upload-image"
                  >
                    <Upload className="h-3 w-3 mr-1" />
                    Upload
                  </Button>
                  <input
                    id="image-file-input"
                    type="file"
                    accept="image/*"
                    onChange={handleImageFileChange}
                    className="hidden"
                    data-testid="input-image-file"
                  />
                </div>
              )}

              <div className="space-y-2">
                <Label htmlFor="image" className="text-xs text-muted-foreground">Or paste image URL</Label>
                <Input 
                  id="image" 
                  placeholder="https://..." 
                  value={formData.image}
                  onChange={(e) => {
                    setFormData(prev => ({ ...prev, image: e.target.value }));
                    if (e.target.value) {
                      setImagePreview(e.target.value);
                    }
                  }}
                  data-testid="input-resource-image" 
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="external-url">External URL *</Label>
              <Input 
                id="external-url" 
                placeholder="https://..." 
                value={formData.externalUrl}
                onChange={(e) => setFormData(prev => ({ ...prev, externalUrl: e.target.value }))}
                data-testid="input-resource-url" 
              />
            </div>

          </div>
          <DialogFooter>
            <Button variant="outline" onClick={handleCloseDialog} data-testid="button-cancel">
              Cancel
            </Button>
            <Button 
              onClick={handleSubmit} 
              disabled={createMutation.isPending || updateMutation.isPending || isUploadingImage}
              data-testid="button-save-resource"
            >
              {isUploadingImage ? "Uploading..." : (createMutation.isPending || updateMutation.isPending ? "Saving..." : (editingResource ? "Update" : "Create"))}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <AlertDialog open={!!deleteResource} onOpenChange={() => setDeleteResource(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Resource</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete "{deleteResource?.title}"? This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel data-testid="button-cancel-delete">Cancel</AlertDialogCancel>
            <AlertDialogAction 
              onClick={handleDelete}
              disabled={deleteMutation.isPending}
              data-testid="button-confirm-delete"
            >
              {deleteMutation.isPending ? "Deleting..." : "Delete"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

